import{_ as e,o as a,c as i,ag as d}from"./chunks/framework.Bb4_ZWqO.js";const p=JSON.parse('{"title":"Contributing","description":"Development setup, quality gate, build commands, and PR guidelines.","frontmatter":{"title":"Contributing","order":8,"description":"Development setup, quality gate, build commands, and PR guidelines."},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md"}'),s={name:"contributing.md"};function o(n,t,r,l,c,h){return a(),i("div",null,[...t[0]||(t[0]=[d(`<h1 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h1><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>Requires <strong>Node.js 22 or later</strong> (tested on Node 22 LTS and Node 24).</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/mayanklahiri/datasole.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> datasole</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span></code></pre></div><p><code>npm install</code> automatically sets up git hooks via husky.</p><h2 id="quality-gate" tabindex="-1">Quality Gate <a class="header-anchor" href="#quality-gate" aria-label="Permalink to &quot;Quality Gate&quot;">​</a></h2><p>The <strong>quality gate</strong> is the single command that validates the entire project:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gate</span></span></code></pre></div><p>It runs the following pipeline, in order, and stops on the first failure:</p><table tabindex="0"><thead><tr><th>Step</th><th>Command</th><th>What it checks</th></tr></thead><tbody><tr><td>1. Clean</td><td><code>clean</code></td><td>Remove all build artifacts</td></tr><tr><td>2. Format</td><td><code>format:check</code></td><td>Prettier formatting</td></tr><tr><td>3. Lint</td><td><code>lint</code></td><td>ESLint + TypeScript (<code>tsc --noEmit</code>)</td></tr><tr><td>4. Build</td><td><code>build</code></td><td>Rollup multi-target bundles (6 outputs)</td></tr><tr><td>5. Unit tests</td><td><code>test --coverage</code></td><td>Vitest + v8 coverage</td></tr><tr><td>6. E2E tests</td><td><code>test:e2e</code></td><td>Playwright + headless Chromium + production bundle</td></tr><tr><td>7. Metrics</td><td><code>collect-metrics</code></td><td>Bundle sizes, coverage, e2e results → <code>reports/</code></td></tr><tr><td>8. Docs</td><td><code>docs:build</code></td><td>Generate static documentation site</td></tr><tr><td>9. Summary</td><td><code>gate:summary</code></td><td>Print pass/fail with statistics</td></tr></tbody></table><p>On success, the gate prints a summary with bundle sizes, coverage percentages, doc page counts, and a <code>GATE PASSED</code> status.</p><p><code>npm run dist</code> is an alias for <code>npm run gate</code>.</p><h3 id="when-the-gate-runs-automatically" tabindex="-1">When the gate runs automatically <a class="header-anchor" href="#when-the-gate-runs-automatically" aria-label="Permalink to &quot;When the gate runs automatically&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trigger</th><th>What runs</th><th>How</th></tr></thead><tbody><tr><td><strong>Pre-commit</strong></td><td>Format + lint staged files</td><td><code>lint-staged</code> via husky</td></tr><tr><td><strong>Pre-push</strong></td><td>Full quality gate</td><td><code>npm run gate</code> via husky</td></tr><tr><td><strong>CI</strong></td><td>Full quality gate</td><td>GitHub Actions on push/PR to <code>main</code></td></tr><tr><td><strong>Publish</strong></td><td>Full quality gate</td><td><code>prepublishOnly</code> hook</td></tr></tbody></table><h3 id="quick-commands-for-development" tabindex="-1">Quick commands for development <a class="header-anchor" href="#quick-commands-for-development" aria-label="Permalink to &quot;Quick commands for development&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>npm run build</code></td><td>Build all targets (no lint/test)</td></tr><tr><td><code>npm test</code></td><td>Run unit tests only</td></tr><tr><td><code>npm run test:watch</code></td><td>Unit tests in watch mode</td></tr><tr><td><code>npm run test:e2e</code></td><td>E2E tests only (builds first)</td></tr><tr><td><code>npm run lint</code></td><td>ESLint + type check only</td></tr><tr><td><code>npm run format</code></td><td>Auto-format all files</td></tr><tr><td><code>npm run format:check</code></td><td>Check formatting without fixing</td></tr><tr><td><code>npm run docs:build</code></td><td>Build docs site only</td></tr><tr><td><code>npm run docs:preview</code></td><td>Preview docs site locally</td></tr><tr><td><code>npm run gate</code></td><td><strong>Full quality gate</strong></td></tr></tbody></table><h2 id="learning-the-codebase" tabindex="-1">Learning the Codebase <a class="header-anchor" href="#learning-the-codebase" aria-label="Permalink to &quot;Learning the Codebase&quot;">​</a></h2><p>If you&#39;re new to datasole:</p><ol><li>Read the <a href="./tutorials">Tutorials</a> — they show every feature with runnable code</li><li>Read the <a href="./architecture">Architecture</a> — the learning path diagram shows how concepts connect</li><li>Read the <a href="./decisions">ADRs</a> — they explain <em>why</em> the code is structured this way</li></ol><h2 id="architecture-decisions" tabindex="-1">Architecture Decisions <a class="header-anchor" href="#architecture-decisions" aria-label="Permalink to &quot;Architecture Decisions&quot;">​</a></h2><p>All ADRs are in <code>docs/decisions.md</code>. <strong>Read them before making structural changes.</strong></p><p>If your change involves an architectural decision:</p><ol><li>Add a new ADR section to <code>docs/decisions.md</code></li><li>Use the next sequential number (e.g., ADR-018)</li><li>Include: Status, Date, Context, Decision, Consequences</li><li>Reference the ADR number in your commit message</li></ol><h2 id="pr-guidelines" tabindex="-1">PR Guidelines <a class="header-anchor" href="#pr-guidelines" aria-label="Permalink to &quot;PR Guidelines&quot;">​</a></h2><ol><li><strong>Run <code>npm run gate</code> locally</strong> — it must pass before opening a PR</li><li>Add/update tests for any new functionality</li><li>Update relevant <code>docs/*.md</code> files — especially tutorials and examples if your change adds user-facing features</li><li>If your change involves an architectural decision, add an ADR to <code>docs/decisions.md</code></li><li>Include the ADR number in the commit message if applicable</li></ol><h2 id="git-hooks" tabindex="-1">Git Hooks <a class="header-anchor" href="#git-hooks" aria-label="Permalink to &quot;Git Hooks&quot;">​</a></h2><p>Hooks are managed by <a href="https://typicode.github.io/husky/" target="_blank" rel="noreferrer">husky</a> and installed automatically by <code>npm install</code>:</p><ul><li><strong>pre-commit</strong>: Runs <code>lint-staged</code> — auto-formats and lints only staged <code>.ts</code> files. Fast (~2s).</li><li><strong>pre-push</strong>: Runs <code>npm run gate</code> — the full quality pipeline. Takes ~30s. Prevents pushing broken code.</li></ul><p>To bypass hooks in an emergency: <code>git push --no-verify</code> (discouraged).</p><h2 id="documentation-style" tabindex="-1">Documentation Style <a class="header-anchor" href="#documentation-style" aria-label="Permalink to &quot;Documentation Style&quot;">​</a></h2><p>When writing or updating docs:</p><ul><li>Every feature should have at least one <strong>runnable example</strong> (both server and client code)</li><li>Examples should be as short as possible while remaining complete and copy-pasteable</li><li>Cross-reference related tutorials: <code>&gt; **Tutorial:** [Name](tutorials.md#anchor)</code></li><li>If adding a new pattern, add it to <code>docs/tutorials.md</code> (progressive build-up) and <code>docs/examples.md</code> (standalone recipe)</li></ul>`,32)])])}const g=e(s,[["render",o]]);export{p as __pageData,g as default};
